// FORMAT THE FINAL WHATSAPP RESULT MESSAGE
// Adapted from Workflow 3's Format AI Response pattern

const item = $input.first().json;

const score = item.finalScore;
const percentile = item.percentile;
const percentileLabel = item.percentileLabel;
const rank = item.rank;
const total = item.totalCandidates;
const probability = item.probability;
const userName = item.userName;
const targetRole = item.targetRole;
const ai = item.ai_analysis;

// Build score bar
const filled = Math.round(score / 10);
const empty = 10 - filled;
const scoreBar = '█'.repeat(filled) + '░'.repeat(empty);

// Build rejection reasons
let rejectionBlock = '';
if (ai && ai.rejection_reasons) {
  ai.rejection_reasons.slice(0, 3).forEach((r, i) => {
    rejectionBlock += `${i + 1}. ${r.reason}\n`;
  });
}

// Build fixes
let fixesBlock = '';
if (ai && ai.fixes) {
  ai.fixes.slice(0, 3).forEach((f, i) => {
    fixesBlock += `${i + 1}. ${f.fix}\n`;
  });
}

// One-liner
const oneLiner = ai?.one_liner || 'Your resume needs targeted improvements for this role.';

const message = `🏆 *CAREER RANK REPORT*
━━━━━━━━━━━━━━━━━━

👤 *${userName}*
🎯 Role: *${targetRole}*

📊 *Your Score: ${score}/100*
${scoreBar}

📈 Percentile: ${percentileLabel} *${percentile}*
🏅 Rank: *#${rank}* out of ${total}+ candidates
⚡ Interview Probability: *${probability}*

━━━━━━━━━━━━━━━━━━
❌ *WHY YOU'RE GETTING REJECTED:*

${rejectionBlock}
💡 _${oneLiner}_

━━━━━━━━━━━━━━━━━━
✅ *WHAT TO FIX:*

${fixesBlock}
━━━━━━━━━━━━━━━━━━
🚀 *Want to improve your rank?*

Get personalized job recommendations 👇
🔗 https://meracareer.io

━━━━━━━━━━━━━━━━━━
📲 *Share this with friends!*
Ask them to type *CHECK MY RANK*`;

// Reset user session state
const staticData = $getWorkflowStaticData('global');
if (staticData.sessions && staticData.sessions[item.from]) {
  staticData.sessions[item.from].state = 'IDLE';
}

return [{
  json: {
    from: item.from,
    message: message
  }
}];
